import javax.net.ssl.*;
import java.io.*;
import java.util.concurrent.*;
import java.security.MessageDigest;  // for SHA256 hashing of incoming data from clients, not the server side itself to verify integrity failure A08_IntegrityFailure as we are only using built-in classes here and no ORM tools or external libraries like Hibernate
import java.security.cert.*;  
 
class java_42612_SocketServer_A08 {
    private final ExecutorService pool = Executors.newFixedThreadPool(5); // Create a threadpool to handle incoming connections in parallel from clients, not necessarily the server itself which runs here for handling of client requests concurrently only using this class and built-in java classes alone (no external frameworks)
    private SSLServerSocket sslServerSocket;  // Server socket connected with Client via Secure Socket Layer(SSL), it uses KeyStore/truststore in case you want to enable mutual authentication between server & client.
    
   public void startServing() throws IOException {                   // Start the serving process, make sure your machine has a certificate for SSL and trusted Certificate store configured properly on all clients connecting through this secure socket layer or else exceptions will be thrown due incorrect CA bundle (not allowed by default in JDK)  -Djavax.net.ssl.trustStore= truststore file location
        KeyStore keyStore = KeyStore.getInstance("JKS");    // Setup of Keystore and Trust store for SSL setup, you need to provide your own keystore & trusted certificates files here or else it won't work properly due incorrect keys/certificate bundle (not allowed by default in JDK)
        keyStore.load(new FileInputStream("path-to-your-keystore"), "password".toCharArray());   //provide your own keystores & passwords here, or else it won't work properly due incorrect keys/certificate bundle (not allowed by default in JDK)
        TrustStore trustStore = TrustStore.getInstance("JKS");   
        trustStore.load(new FileInputStream("/path-to-your-truststore"), "password".toCharArray());  //provide your own trusted certificates & passwords here, or else it won't work properly due incorrect keys/certificate bundle (not allowed by default in JDK)
        SSLServerSocketFactory sslServerSocketFactory =  
                (SSLServerSocketFactory) SSLServerSocketFactory.getDefault();  //Setup the Server Socket Factory which will use KeyStore & Trust Store for Encryption and Decrypting of incoming data from clients, not actually serving any files here but merely ensuring encryption/decrypted client-server communication is secure due to proper setup with Keystore /Truststore
        sslServerSocket = (SSLServerSocket)sslServerSocketFactory.createServerSocket(1234);    //Setup the Server Socket on port 1234 and make it listen for incoming connections only, not serving files here but merely ensuring connection/disconnection of client-server communication is secure due to proper setup with Keystore /Truststore
        sslServerSocket.setNeedClientAuth(true);   // Enable mutual authentication as per your requirement in case all clients have correct CA certificates (not allowed by default in JDK)  -Djavax.net.ssl.trustStore= truststore file location and client CAs from the server's certificate to enable SSL
        sslServerSocket.setKeyStore(keyStore);   // Set Key Store for Server Socket so clients can authenticate itself via certificates, not actually serving any files here but merely ensuring connection/disconnection of client-server communication is secure due to proper setup with Keystore /Truststore
        sslServerSocket.setKeyStorePassword("password".toCharArray());  //provide your own passwords or else it won't work properly because incorrect keys store & certificate bundle (not allowed by default in JDK) -Djavax.net.ssl.keyStorePassword=pass-word
        sslServerSocket.setTrustStore(trustStore);   // Setup Trust Store for Server Socket, used to validate the identity of clients after successful authentication via client certificates (not allowed by default in JDK) -Djavax.net.ssl.trustStorePassword=pass-word
        SSLSocket socket = null;  // Declare and initialize a new sslServer_socket variable that will hold our incoming secure Socket connection from the clients after successful authentication via client certificates (not allowed by default in JDK) -Djavax.net.ssl.socketFactory= custom server-side factory
         while(( socket = ((SSLServerSocket) sslServerSocket).accept()) !=  null){ // This will keep running until a valid secure Socket connection from clients is established, not serving files here but merely ensuring that client & servers are secured due to proper setup with Keystore /Truststore and mutual authentication
                System.out.println("Got Connection From Client");    // ACTION: Logic for handling the connected socket should go in this while loop only using built-in java classes  - No external frameworks or ORM tools needed here like Hibernate is used to manipulate data, just validating & managing clients and server securely
                pool.execute(new SocketWorkerThread((socket))); // Use of threadpool ExecutorService for handling multiple client requests concurrent in different threads which will be done by this code only using built-in java classes  - No external frameworks or ORM tools needed here like Hibernate is used to manipulate data, just validating & managing clients and server securely
        }       // END while loop     End of Serving Process    Use of Built In Java Classes Only. This code will only run if it's a part of main method with exception handling properly added for security-sensitive operations related to A08_IntegrityFailure (only using java built in classes and no external libraries or frameworks)
   }  // END startServing() Method    End Socket Server Code. This code is only valid when used within a main method with exception handling properly added for security-sensitive operations related to A08_IntegrityFailure (only using java built in classes and no external libraries or frameworks)
}